  ('real-estate-moex-01124', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲男20歲，乙女15歲，二人一見鍾情，決定廝守終身，於是結婚。乙女尚未滿適婚年齡，亦尚未 懷孕。下列敘述何者正確？', '["乙女未滿適婚年齡，其結婚無效", "乙女未滿適婚年齡，乙女得不經法院逕行撤銷結婚", "乙女未滿適婚年齡，乙女得向法院請求撤銷結婚", "乙女未滿適婚年齡，需經法定代理人同意始得撤銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01125', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於姻親關係，下列敘述何者正確？', '["甲之兒子乙與丙女結婚，甲與丙無姻親關係", "甲之配偶乙，乙有一個哥哥丙，甲與丙無姻親關係", "甲之配偶乙，乙有一個哥哥丙，丙有配偶丁，甲與丁無姻親關係", "甲之兒子乙與丙女結婚，丙女之父親為丁，甲與丁無姻親關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01126', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲男與乙女未結婚，但生下丙。下列敘述何者正確？', '["乙女必須認領丙，丙才視為乙之婚生子女", "縱使甲與乙嗣後結婚，丙仍是非婚生子女", "甲死後，丙得向甲之繼承人提起認領之訴", "甲認領丙後，無論如何絕對不得撤銷認領"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01127', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於不動產所有權取得時效，下列敘述何者錯誤？', '["應以所有之意思", "應和平公然繼續占有", "應占有他人未登記之不動產", "時效完成即取得不動產所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01128', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲死亡時，遺有財產新臺幣 500 萬元。甲有子女乙、丙二人為其法定繼承人，甲生前立有遺囑，載 明若乙之兒子丁考上不動產經紀人，無償給與丁新臺幣 100 萬元。甲死亡時，丁尚未考上不動產經 紀人。下列敘述何者正確？', '["遺囑於甲死亡時發生效力，丁取得新臺幣100萬元之所有權", "遺囑於丁考上不動產經紀人時發生效力，丁取得新臺幣100萬元之所有權", "遺囑於甲死亡時發生效力，丁取得請求給付新臺幣100萬元之債權", "遺囑於丁考上不動產經紀人時發生效力，丁取得請求給付新臺幣100萬元之債權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01129', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '19歲之甲與20歲之乙訂立買賣契約，將一宗土地賣給乙，並將土地所有權移轉登記給乙。下列敘述 何者正確？', '["買賣契約及所有權移轉契約，均需得甲之法定代理人書面或非書面之允許，始生效力", "買賣契約及所有權移轉契約，均需得甲之法定代理人書面允許，一定要書面允許始生效", "買賣契約需得甲之法定代理人書面允許，始生效力；所有權移轉契約則無須書面允許，亦生效力", "所有權移轉契約需得甲之法定代理人書面允許，始生效力；買賣契約則無須書面允許，亦生效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01130', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲死亡後，其子女乙、丙二人為繼承人。甲留有房屋一棟市值新臺幣 500 萬元，且甲對丁有新臺幣 500萬元債權，已屆清償期。遺產分割時，乙分得房屋，丙分得債權。乙對丁何時之支付能力應負擔 保責任？', '["乙就遺產分割時丁之支付能力負擔保之責", "乙就債務實際清償時丁之支付能力負擔保之責", "乙就清償期屆滿時丁之支付能力負擔保之責", "乙就甲死亡時丁之支付能力負擔保之責"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01131', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲與乙結婚，並無子女，甲死亡時，甲之父母丙、丁尚健在；設甲遺有財產新臺幣1200萬元，並無 任何債務。請問如何繼承？', '["乙得新臺幣600萬元，丙、丁各得新臺幣300萬元", "乙得新臺幣800萬元，丙、丁各得新臺幣200萬元", "乙得新臺幣1200萬元，丙、丁各得新臺幣0元", "乙、丙、丁各得新臺幣400萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01132', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關法人之敘述，何者錯誤？', '["社團法人應設章程", "以遺囑捐助設立財團法人者，不以訂立捐助章程為必要", "應設董事", "應設監察人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01133', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲於98年6月1日受乙脅迫，約定將甲所有之動產以遠低於市價之價格出售予乙。事經2年餘後，乙請 求甲依約交付該動產。下列敘述何者正確？', '["甲得於撤銷原先受脅迫所為之意思表示後，拒絕給付", "甲得撤銷受脅迫意思表示之權利行使期間已過，應為給付", "即使甲未撤銷受脅迫所為之意思表示，仍得拒絕給付", "甲得主張與乙所締結之契約自始無效，拒絕給付"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
